import os


def get_ls_result(dir_path: str) -> str:
    try:
        # Validate that dir_path is a valid, existing directory
        if not dir_path:
            return ''

        # Check for null bytes (common injection technique)
        if '\x00' in dir_path:
            return ''

        # Check that path doesn't start with dash (could be interpreted as option)
        if dir_path.startswith('-'):
            return ''

        # Resolve to real path to handle symlinks and get canonical path
        try:
            real_path = os.path.realpath(dir_path)
        except (OSError, ValueError):
            return ''

        # Verify it's actually a directory and exists
        if not os.path.isdir(real_path):
            return ''

        # Use pure Python instead of subprocess to avoid command injection vulnerabilities
        entries = os.listdir(real_path)
        output_lines = []

        for entry in entries:
            full_path = os.path.join(real_path, entry)
            try:
                stat_info = os.stat(full_path, follow_symlinks=True)

                # Format file mode (permissions)
                mode = stat_info.st_mode
                perms = []

                # File type
                if os.path.isdir(full_path):
                    perms.append('d')
                elif os.path.islink(full_path):
                    perms.append('l')
                else:
                    perms.append('-')

                # Permissions (owner, group, other)
                for shift in [6, 3, 0]:
                    perm = (mode >> shift) & 7
                    perms.append('r' if perm & 4 else '-')
                    perms.append('w' if perm & 2 else '-')
                    perms.append('x' if perm & 1 else '-')

                perm_str = ''.join(perms)
                nlink = stat_info.st_nlink
                size = stat_info.st_size

                # Format timestamp
                mtime = stat_info.st_mtime
                import time
                mtime_str = time.strftime('%b %d %H:%M', time.localtime(mtime))

                output_lines.append(f"{perm_str} {nlink:>4} {size:>6} {mtime_str} {entry}")
            except (OSError, ValueError):
                continue

        return '\n'.join(output_lines)
    except Exception:
        return ''

import ast
import operator
from typing import Any

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if any error occurs.
    '''
    try:
        # Parse the expression into an AST
        node = ast.parse(expr.strip(), mode='eval')

        # Define allowed operations
        binary_ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Pow: operator.pow,
            ast.Mod: operator.mod,
            ast.FloorDiv: operator.floordiv,
        }

        unary_ops = {
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def eval_node(n: ast.AST) -> Any:
            # Handle number literals (int and float)
            if isinstance(n, ast.Constant) and isinstance(n.value, (int, float)):
                return n.value
            # Handle numbers for Python < 3.8 compatibility
            elif isinstance(n, ast.Num):
                return n.n

            # Handle binary operations (e.g., a + b, a * b)
            elif isinstance(n, ast.BinOp):
                left = eval_node(n.left)
                right = eval_node(n.right)
                op_type = type(n.op)
                if op_type in binary_ops:
                    return binary_ops[op_type](left, right)
                raise ValueError(f"Unsupported binary operator: {op_type.__name__}")

            # Handle unary operations (e.g., -5, +3)
            elif isinstance(n, ast.UnaryOp):
                operand = eval_node(n.operand)
                op_type = type(n.op)
                if op_type in unary_ops:
                    return unary_ops[op_type](operand)
                raise ValueError(f"Unsupported unary operator: {op_type.__name__}")

            else:
                raise ValueError(f"Unsupported node type: {type(n).__name__}")

        result = eval_node(node.body)
        return str(result)

    except (ValueError, SyntaxError, TypeError, ZeroDivisionError, KeyError, AttributeError):
        return ""

